using System;
using System.Collections.Generic;
class Program {
  static void Main() {
    var line = Console.ReadLine().Trim();
    var parts = line.Split('|');
    var nums = Array.ConvertAll(parts[0].Split(','), int.Parse);
    int t = int.Parse(parts[1]);
    var seen = new Dictionary<int, int>();
    for (int i = 0; i < nums.Length; i++) {
      int need = t - nums[i];
      if (seen.ContainsKey(need)) { Console.WriteLine(seen[need] + "," + i); return; }
      seen[nums[i]] = i;
    }
  }
}
